#include <bits/stdc++.h>
using namespace std;
int n,a[10],b[10],f[10],use[10];
long long ans=(1LL<<61)-1,len=0;
void dfs(int x){
    if(x>n){
        ans=min(ans,len);
        //cout<<len<<endl;
        return;
    }
    for(int i=1;i<=n;i++){
        if(!use[i]){
            use[i]=1,f[x]=i,len++;
            if(x>1)len+=max(b[f[x-1]],a[i]);
            dfs(x+1);
            use[i]=0,f[x]=0,len--;
            if(x>1)len-=max(b[f[x-1]],a[i]);
        }
    }
}
int main(){
    cin>>n;
    for(int i=1;i<=n;i++)cin>>a[i];
    for(int i=1;i<=n;i++)cin>>b[i];
    //cout<<ans<<endl;
    dfs(1);
    cout<<ans;
    return 0;
}
